    let peakIndex = 0;
    // The array is strictly increasing until the peak, and strictly decreasing after.
    // We find the first element that is less than its previous element.
    // Since n >= 3, there must be a peak.
    for (let i = 1; i < n; i++) {
        if (nums[i] < nums[i - 1]) {
            peakIndex = i - 1;
            break;
